import java.util.Scanner;

public class SecureBuffer {

    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);

        System.out.println("Enter a string: ");
        String userInput = scanner.nextLine();

        // Define a safe buffer size
        int bufferSize = Math.min(userInput.length(), 10); // Limit buffer size to 10 characters

        char[] buffer = new char[bufferSize];

        userInput.getChars(0, bufferSize, buffer, 0); // Copy only up to bufferSize characters

        System.out.println("Buffer content: " + new String(buffer));
    }
}

### Explanation:
취약유형: Buffer Overflow
